#include <bits/stdc++.h>
using namespace std;

int main() {
    string s;
    getline(cin, s);

    // 去掉末尾的句号
    if (!s.empty() && s.back() == '.') s.pop_back();

    stringstream ss(s);
    string word, longest;
    while (ss >> word) {
        if (word.length() > longest.length()) longest = word;
    }
    cout << longest << endl;
    return 0;
}
